function NewsFeed() {
  const [topic, setTopic] = React.useState('REPLACE_WITH_TOPIC');
  const [articles, setArticles] = React.useState([]);
  const [loading, setLoading] = React.useState(false);

  React.useEffect(() => { search(); }, []);

  const search = () => {
    setLoading(true);
    // Using Hacker News Algolia as a free, reliable news source
    fetch(`https://hn.algolia.com/api/v1/search?query=${encodeURIComponent(topic||'technology')}&hitsPerPage=12`)
      .then(r=>r.json())
      .then(d=>{setArticles(d.hits||[]);setLoading(false);})
      .catch(()=>setLoading(false));
  };

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <span style={{fontSize:18,fontWeight:700}}>News Feed</span>
        <div style={{display:'flex',gap:8}}>
          <input value={topic} onChange={e=>setTopic(e.target.value)} onKeyDown={e=>e.key==='Enter'&&search()}
            style={{padding:'6px 10px',borderRadius:6,border:'1px solid #ccc',fontSize:13,width:140}}
            placeholder="Topic…"/>
          <button onClick={search}
            style={{padding:'6px 12px',borderRadius:6,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer',fontSize:13}}>
            Search
          </button>
        </div>
      </div>
      {loading && <div style={{textAlign:'center',color:'#888'}}>Loading…</div>}
      <div style={{flex:1,overflow:'auto'}}>
        {articles.map(a=> (
          <a key={a.objectID} href={a.url} target="_blank" rel="noopener noreferrer"
            style={{display:'block',padding:'10px 0',borderBottom:'1px solid #eee',textDecoration:'none',color:'inherit'}}>
            <div style={{fontSize:14,fontWeight:600,color:'#007AFF',marginBottom:4}}>{a.title}</div>
            <div style={{fontSize:12,color:'#888',display:'flex',gap:8}}>
              <span>{a.points} points</span>
              <span>{a.author}</span>
              <span>{a.num_comments} comments</span>
            </div>
          </a>
        ))}
      </div>
    </div>
  );
}
render(<NewsFeed/>);
